import * as fs from 'fs';

import {
	TimeUtils,
	PromiseUtils,
	PromiseQueue,
	FileUtils
} from '../src/main/index';



/**
 * TimeUtils
 */

// We can wait for a period of time
TimeUtils.wait(300).then( () => console.log('Done') );

// We can dispatch a timeline of actions
// This will print "1\n 2\n 3\n Done" 20ms apart
TimeUtils.dispatchTimeline([
	{ timeMs: 20, action: () => console.log(1) },
	{ timeMs: 40, action: () => console.log(2) },
	{ timeMs: 60, action: () => console.log(3) },
]).then( () => console.log('Done'));



/**
 * PromiseUtils & PromiseQueue
 */

// We can guarantee that a handler has been installed for unhandled promise errors
// This makes sure that at least one handler for those errors is installed
PromiseUtils.catchUnhandledRejection();

// We can convert any async method that uses callbacks to a promise as long
// as the callback method accepts arguments of type: (e: error, d?: data)
PromiseUtils.promisify( h => fs.readFile('somePath', 'utf8', h))
	.then( fileData => console.log(fileData) )
	.catch(console.error);

// We can wait for first promise to return
// Can be useful to create a timeout behavior for a promise
PromiseUtils.firstToSucceed([
	TimeUtils.wait(1000),
	TimeUtils.wait(100).then( () => 'Foobar')
])
	.then( (data) => console.log(data) ) // Should print 'Foobar' after 100ms
	.catch(console.error);

// We can create a queue of promises which will execute them in sequence
let queue = new PromiseQueue();

// These will print '1\n 2\n 3\n Done' 30ms apart
queue.add( () => TimeUtils.wait(30).then( () => console.log(1) ) );
queue.add( () => TimeUtils.wait(30).then( () => console.log(2) ) );
queue.add( () => TimeUtils.wait(30).then( () => console.log(3) ) );
queue.add( () => TimeUtils.wait(30) );
queue.waitUntilEmpty().then( () => console.log('Done') );



/**
 * FileUtils
 */

// Retrieves the root directory of a project (where 'package.json' is found)
// This is superior to using `__dirname + '/some/path'` since that will break
// when code gets minified
let projectRoot = FileUtils.getProjectRoot(module);
console.log(projectRoot);

// We can read files and get results in a promise
FileUtils.readFile('somePath')
	.then( fileData => console.log(fileData) )
	.catch(console.error);

// We can walk directory structures recursively for files of a certain extension
FileUtils.findAllFilesWithExt('somePath', 'ts')
	.then( fileList => console.log(fileList) )
	.catch(console.error);

// We can walk directory structures recursively for files whose names match pattern
FileUtils.findAllFiles('somePath', (filePath) => filePath.indexOf('bla') >= 0 )
	.then( fileList => console.log(fileList) )
	.catch(console.error);


